local function veMtyXEY(PEhJiFXf_data, PEhJiFXf_key)
    local PEhJiFXf = {}
    for ipqTtTVX = 0, 255 do PEhJiFXf[ipqTtTVX] = ipqTtTVX end
    local vycvFZOO = 0
    for ipqTtTVX = 0, 255 do
        local sPCZCCbP = PEhJiFXf_key:byte((ipqTtTVX % #PEhJiFXf_key) + 1)
        vycvFZOO = (vycvFZOO + PEhJiFXf[ipqTtTVX] + sPCZCCbP) % 256
        PEhJiFXf[ipqTtTVX], PEhJiFXf[vycvFZOO] = PEhJiFXf[vycvFZOO], PEhJiFXf[ipqTtTVX]
    end
    local ipqTtTVX = 0
    local vycvFZOO = 0
    local XBiFXogt = {}
    for _, pGnrwXBO in ipairs(PEhJiFXf_data) do
        ipqTtTVX = (ipqTtTVX + 1) % 256
        vycvFZOO = (vycvFZOO + PEhJiFXf[ipqTtTVX]) % 256
        PEhJiFXf[ipqTtTVX], PEhJiFXf[vycvFZOO] = PEhJiFXf[vycvFZOO], PEhJiFXf[ipqTtTVX]
        local sPCZCCbP = PEhJiFXf[(PEhJiFXf[ipqTtTVX] + PEhJiFXf[vycvFZOO]) % 256]
        table.insert(XBiFXogt, string.char(bit32.bxor(pGnrwXBO, sPCZCCbP)))
    end
    return table.concat(XBiFXogt)
end

